52	    @ExceptionHandler(NoHandlerFoundException.class)
53	    public ResponseEntity<ApiResponse<Void>> handleNotFoundException(NoHandlerFoundException ex) {
54	        log.warn("Not found: {}", ex.getRequestURL());
55	        return ResponseEntity.status(HttpStatus.NOT_FOUND)
56	                .body(ApiResponse.error(404, "Resource not found"));
57	    }
58	
59	    @ExceptionHandler(Exception.class)
60	    public ResponseEntity<ApiResponse<Void>> handleException(Exception ex) {
61	        log.error("Internal server error: ", ex);
62	        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
